1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life - Next Generation", () => {
5	  it("should return empty array for empty grid", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("should kill a single live cell with no neighbors", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("should kill cells with only one neighbor (underpopulation)", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("should keep alive a live cell with 2 live neighbors (survival)", () => {
15	    expect(nextGeneration([[0, 0], [0, 1], [0, 2]])).toContainEqual([0, 1]);
16	  });
17	  it("should keep alive a live cell with 3 live neighbors (survival)", () => {
18	    expect(nextGeneration([[0, 0], [1, 0], [2, 0], [1, 1]])).toContainEqual([1, 0]);
19	  });
20	  it("should kill a live cell with 4 live neighbors (overpopulation)", () => {
21	    expect(nextGeneration([[1, 0], [0, 1], [2, 1], [1, 2], [1, 1]])).not.toContainEqual([1, 1]);
22	  });
23	  it("should bring a dead cell with exactly 3 live neighbors to life (reproduction)", () => {
24	    expect(nextGeneration([[0, 0], [1, 0], [0, 1]])).toContainEqual([1, 1]);
25	  });
26	  it("should keep a block pattern unchanged (still life)", () => {
27	    const result = nextGeneration([[0, 0], [1, 0], [0, 1], [1, 1]]);
28	    expect(result).toHaveLength(4);
29	    expect(result).toEqual(expect.arrayContaining([[0, 0], [1, 0], [0, 1], [1, 1]]));
30	  });
31	  it("should oscillate a vertical blinker into a horizontal blinker", () => {
32	    const result = nextGeneration([[0, 0], [0, 1], [0, 2]]);
33	    expect(result).toHaveLength(3);
34	    expect(result).toEqual(expect.arrayContaining([[-1, 1], [0, 1], [1, 1]]));
35	  });
36	});
